import { afterEach, describe, test } from "node:test";
import assert from "node:assert/strict";
import fs from "fs";
import os from "os";
import path from "path";
import { detectContentType, detectGaps, discoverScopeFiles } from "../content/analyzer.js";
import { extractSpec } from "../content/parser.js";
import { buildAlgorithmQuestions, buildQuestions, polishContent } from "../content/questionBuilder.js";
import { buildDrillCustomContent, buildRecallContext } from "../drills/contentBuilder.js";
import { assessComplexity } from "../exercises/assessment.js";
import { buildExerciseMarkdown } from "../exercises/markdown.js";
import { buildScopeContent, deriveSessionGoal } from "../scope/builder.js";
import type { Evaluation, Exercise, Mistake } from "@mock-interview/shared";

const tempDirs: string[] = [];

afterEach(() => {
  for (const dir of tempDirs.splice(0)) {
    fs.rmSync(dir, { recursive: true, force: true });
  }
});

function makeTempDir(prefix: string): string {
  const dir = fs.mkdtempSync(path.join(os.tmpdir(), prefix));
  tempDirs.push(dir);
  return dir;
}

describe("content extraction modules", () => {
  const apiSpec = `
POST /payments (create payment)
GET /payments/{id} (fetch payment)

Payment contains the fields amount (number), currency (string), status (string)

Business rules
- amount must be greater than zero
- currency is required
- data is kept in memory on startup
`;

  test("extractSpec pulls endpoints, models, rules, and notes", () => {
    const spec = extractSpec(apiSpec);
    assert.equal(spec.endpoints.length, 2);
    assert.equal(spec.models[0]?.name, "Payment");
    assert.ok(spec.rules.some((rule) => rule.includes("amount must be greater than zero")));
    assert.ok(spec.notes.some((note) => note.includes("in memory on startup")));
  });

  test("questionBuilder builds polished markdown and api questions", () => {
    const spec = extractSpec(apiSpec);
    const gaps = detectGaps(apiSpec);
    const polished = polishContent("Payments", apiSpec, "reliability");
    const questions = buildQuestions("Payments", spec, gaps, "reliability");

    assert.match(polished, /# Payments — Structured Spec/);
    assert.match(polished, /## API Endpoints/);
    assert.equal(questions.length, 6);
    assert.match(questions[0], /most critical missing pieces/);
  });

  test("detectContentType routes algorithm content to algorithm question generation", () => {
    const algorithmSpec = `
## Problem Statement
## Constraints
Time: O(n)
Space: O(1)
`;

    assert.equal(detectContentType(algorithmSpec), "algorithm");
    assert.equal(buildAlgorithmQuestions("Rotate Matrix", algorithmSpec, "correctness").length, 6);
  });

  test("discoverScopeFiles ranks topic matches and returns previews", () => {
    const scopeDir = makeTempDir("first-mcp-scope-");
    fs.writeFileSync(path.join(scopeDir, "payments-api.md"), "# Payments API\nCreate and fetch payments\n", "utf-8");
    fs.writeFileSync(path.join(scopeDir, "jwt-auth.md"), "# JWT\nToken validation\n", "utf-8");

    const candidates = discoverScopeFiles("payments api", scopeDir);
    assert.equal(candidates[0]?.filename, "payments-api.md");
    assert.match(candidates[0]?.preview ?? "", /Payments API/);
  });
});

describe("supporting builders", () => {
  test("scope builder derives a goal and renders all sections", () => {
    const goal = deriveSessionGoal("Event Loop", ["microtasks", "macrotasks"], "mixed");
    const content = buildScopeContent({
      topic: "Event Loop",
      focusAreas: ["microtasks", "macrotasks"],
      weakSpots: ["Promise ordering"],
      depth: "mixed",
      outOfScope: ["DOM APIs"],
      sessionGoal: goal,
    });

    assert.match(content, /## Focus Areas/);
    assert.match(content, /## Known Weak Spots/);
    assert.match(content, /Promise ordering/);
  });

  test("drill builder creates recall context and drill content", () => {
    const weakEvals: Evaluation[] = [{
      questionIndex: 0,
      question: "What is a race condition?",
      answer: "Unsure",
      score: 2,
      feedback: "Define it and give an example.",
      needsFollowUp: true,
      strongAnswer: "A race condition occurs when outcome depends on timing.",
    }];
    const mistakes: Mistake[] = [{
      id: "m1",
      mistake: "Confused race condition with deadlock",
      pattern: "Concurrency terms blur together",
      fix: "Explain both with examples before comparing them",
      topic: "java-concurrency",
      createdAt: "2026-01-01T00:00:00.000Z",
    }];

    const recall = buildRecallContext(weakEvals, mistakes);
    const content = buildDrillCustomContent("Java Concurrency", "s1", "2026-01-02T00:00:00.000Z", "2.0", weakEvals, mistakes);

    assert.equal(recall.knownMistakes.length, 1);
    assert.equal(recall.weakAreas[0]?.previousScore, 2);
    assert.match(content, /Known Mistake Patterns/);
    assert.match(content, /Strong answer looks like/);
  });

  test("exercise modules render markdown and assess prerequisites", () => {
    const exercise: Exercise = {
      id: "ex-1",
      name: "Race Condition Lab",
      slug: "race-condition-lab",
      topic: "java-concurrency",
      language: "java",
      difficulty: 4,
      description: "Practice race condition debugging",
      scenario: "Concurrent counter service",
      problemMeaning: ["Shows how unsafe shared state fails under load"],
      tags: ["concurrency"],
      prerequisites: [{ name: "Atomic Counter Basics", reason: "Learn atomic primitives first" }],
      filePath: "java-concurrency/race-condition-lab.md",
      createdAt: "2026-01-01T00:00:00.000Z",
    };

    const markdown = buildExerciseMarkdown(exercise, {
      learningGoal: "Understand race conditions",
      problemStatement: "Fix the counter implementation",
      steps: ["Run the code", "Identify the race", "Fix it"],
      evaluationCriteria: ["Uses atomic or synchronized protection"],
      hints: [],
      relatedConcepts: ["atomicity"],
    });
    const assessment = assessComplexity(exercise.difficulty, exercise.prerequisites, []);

    assert.match(markdown, /# Exercise: Race Condition Lab/);
    assert.equal(assessment.tooHard, true);
    assert.deepEqual(assessment.unmetPrerequisites, ["Atomic Counter Basics"]);
  });
});

// ─────────────────────────────────────────────────────────────────────────────
// content/analyzer.ts
//
// Pure-ish functions that classify content, detect missing topics, and
// discover candidate scope files. File discovery touches disk but is kept
// outside tool wiring so it can be tested independently.
// ─────────────────────────────────────────────────────────────────────────────

import fs from "fs";
import path from "path";

export const GAP_CHECKS: Array<{ label: string; keywords: RegExp }> = [
  { label: "Authentication / authorisation",      keywords: /\b(auth|jwt|oauth|api.?key|bearer|token|security)\b/i },
  { label: "Input validation & error responses",  keywords: /\b(valid|constraint|400|422|error response|bad request)\b/i },
  { label: "HTTP status codes & error schema",    keywords: /\b(status code|4\d\d|5\d\d|error body|error schema)\b/i },
  { label: "Rate limiting / throttling",          keywords: /\b(rate.?limit|throttl|quota)\b/i },
  { label: "Logging & observability",             keywords: /\b(log|metric|trace|observ|monitor|alert)\b/i },
  { label: "Data persistence across restarts",    keywords: /\b(database|db|persist|disk|file|sql|nosql|storage)\b/i },
  { label: "Concurrency & thread safety",         keywords: /\b(thread|concurr|lock|sync|atomic|race)\b/i },
  { label: "Pagination for list endpoints",       keywords: /\b(page|paginate|limit|offset|cursor)\b/i },
  { label: "Versioning strategy (e.g. /v1/)",     keywords: /\/v\d+\/|api.?version/i },
  { label: "Caching strategy",                    keywords: /\b(cache|etag|cache-control|ttl)\b/i },
  { label: "Testing strategy",                    keywords: /\b(unit test|integration test|test coverage|tdd)\b/i },
];

const PREVIEW_LINES = 4;
const SUPPORTED_EXTS = [".md", ".txt", ".yaml", ".yml", ".json"];

export interface ScopeCandidate {
  contentPath: string;
  filename: string;
  preview: string;
  score: number;
}

/** Return labels for topics that are absent from the spec. */
export function detectGaps(content: string): string[] {
  return GAP_CHECKS
    .filter((g) => !g.keywords.test(content))
    .map((g) => g.label);
}

/**
 * Heuristic: if the content has ≥ 2 algorithm signals (Big-O, pattern:, etc.),
 * treat it as an algorithm problem rather than an API spec.
 */
export function detectContentType(content: string): "algorithm" | "api" {
  const algorithmSignals = [
    /##\s+Problem Statement/i,
    /##\s+Constraints/i,
    /##\s+Expected approach/i,
    /##\s+Common mistakes/i,
    /\bTime:\s*O\(/i,
    /\bSpace:\s*O\(/i,
    /\bO\([^)]+\)/,
    /\bpattern:/i,
    /\binvariant:/i,
    /\bedge cases?\b/i,
  ];
  const hits = algorithmSignals.filter((re) => re.test(content)).length;
  return hits >= 2 ? "algorithm" : "api";
}

export function discoverScopeFiles(topic: string, scopeDir: string): ScopeCandidate[] {
  if (!fs.existsSync(scopeDir)) return [];

  const topicWords = topic
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, " ")
    .split(/\s+/)
    .filter((word) => word.length > 1);

  const files = fs.readdirSync(scopeDir)
    .filter((filename) => SUPPORTED_EXTS.some((ext) => filename.endsWith(ext)));

  const candidates: ScopeCandidate[] = files.map((filename) => {
    const normalised = filename.toLowerCase().replace(/[-_.]/g, " ");
    const matched = topicWords.filter((word) => normalised.includes(word));
    const score = topicWords.length > 0 ? matched.length / topicWords.length : 0;

    const fullPath = path.join(scopeDir, filename);
    const raw = fs.readFileSync(fullPath, "utf-8");
    const preview = raw
      .split("\n")
      .map((line) => line.trimEnd())
      .filter((line) => line.length > 0)
      .slice(0, PREVIEW_LINES)
      .join("\n");

    return {
      contentPath: `${path.basename(scopeDir)}/${filename}`,
      filename,
      preview,
      score,
    };
  });

  const matched = candidates
    .filter((candidate) => candidate.score > 0)
    .sort((left, right) => right.score - left.score);

  return matched.length > 0 ? matched : candidates;
}

// ─────────────────────────────────────────────────────────────────────────────
// content/parser.ts
//
// Pure functions that extract structured signals from raw spec text.
// No I/O. No side effects.
// ─────────────────────────────────────────────────────────────────────────────

export interface Endpoint {
  method: string;
  path:   string;
  hint:   string;
}

export interface DataModel {
  name:   string;
  fields: Array<{ name: string; type: string }>;
}

export interface ExtractedSpec {
  endpoints: Endpoint[];
  models:    DataModel[];
  rules:     string[];
  notes:     string[];
}

function capitalise(s: string): string {
  return s.charAt(0).toUpperCase() + s.slice(1);
}

/** Extract HTTP endpoints with optional inline descriptions. */
export function extractEndpoints(content: string): Endpoint[] {
  const re   = /\b(GET|POST|PUT|PATCH|DELETE)\s+(\/[\w/{}:.-]+)(?:\s*\(([^)]*)\))?/gi;
  const seen = new Set<string>();
  const results: Endpoint[] = [];
  for (const m of content.matchAll(re)) {
    const key = `${m[1].toUpperCase()} ${m[2]}`;
    if (!seen.has(key)) {
      seen.add(key);
      results.push({ method: m[1].toUpperCase(), path: m[2], hint: m[3]?.trim() ?? "" });
    }
  }
  return results;
}

/**
 * Extract named data models by scanning for "contains [at least] the fields" anchors,
 * then collecting every "fieldName (Type)" pattern in the following lines until we hit
 * another model anchor, a blank line followed by a capital letter, or a section header.
 * Falls back to a single flat model when no named groups are found.
 */
export function extractModels(content: string): DataModel[] {
  const lines     = content.replace(/\r\n/g, "\n").split("\n");
  const anchorRe  = /\bcontains\s+(?:at\s+least\s+)?the\s+fields\b/i;
  const stopRe    = /^(business rules|#|\* (get|post|put|patch|delete)\b)/i;
  const fieldRe   = /\b([a-z][a-zA-Z]+)\s*\(([^)]+)\)/g;

  function modelNameFrom(line: string): string {
    const before = line.split(/\bcontains\b/i)[0] ?? line;
    return before
      .replace(/^\s*(?:the|a|an)\s+/i, "")
      .trim()
      .replace(/\s+/g, " ") || "Data Model";
  }

  const models: DataModel[] = [];

  for (let i = 0; i < lines.length; i++) {
    if (!anchorRe.test(lines[i])) continue;

    const name   = capitalise(modelNameFrom(lines[i]));
    const fields: Array<{ name: string; type: string }> = [];

    for (let j = i; j < Math.min(i + 10, lines.length); j++) {
      const line = lines[j];
      if (j > i && (stopRe.test(line.trim()) || anchorRe.test(line))) break;
      if (j > i && line.trim() === "" && fields.length > 0) break;
      for (const f of line.matchAll(fieldRe)) {
        if (!fields.find((x) => x.name === f[1])) {
          fields.push({ name: f[1], type: f[2].trim() });
        }
      }
    }

    if (fields.length > 0) models.push({ name: capitalise(name), fields });
  }

  // Fallback: collect all typed fields into one flat model
  if (models.length === 0) {
    const fields: Array<{ name: string; type: string }> = [];
    for (const m of content.matchAll(/\b([a-z][a-zA-Z]+)\s*\(([^)]+)\)/g)) {
      if (!fields.find((f) => f.name === m[1])) {
        fields.push({ name: m[1], type: m[2].trim() });
      }
    }
    if (fields.length > 0) models.push({ name: "Data Fields", fields });
  }

  return models;
}

/**
 * Pull explicit business-rule sentences: constraint language present AND
 * the line is not just a structural description.
 */
export function extractRules(content: string): string[] {
  const structuralRe = /\b(contains|created|contains the fields|contain at least|is calculated|is returned)\b/i;
  return content
    .split(/\n/)
    .map((l) => l.replace(/^[-*•\d.]\s*/, "").trim())
    .filter((l) =>
      l.length > 10 &&
      /\b(should not|must not|cannot|must be|should be|not exceed|no more than|limited to|only if|requires|is forbidden|is required|is mandatory)\b/i.test(l) &&
      !structuralRe.test(l)
    )
    .slice(0, 8);
}

/** Pull implementation notes — "in memory", "framework choice", etc. */
export function extractNotes(content: string): string[] {
  return content
    .split(/\n/)
    .map((l) => l.trim())
    .filter((l) =>
      l.length > 10 &&
      /\b(in memory|on startup|on application startup|framework|library|in-memory|cache|no database|no persistence)\b/i.test(l)
    )
    .slice(0, 5);
}

/** Combine all extractors into a single pass. */
export function extractSpec(raw: string): ExtractedSpec {
  return {
    endpoints: extractEndpoints(raw),
    models:    extractModels(raw),
    rules:     extractRules(raw),
    notes:     extractNotes(raw),
  };
}

// ─────────────────────────────────────────────────────────────────────────────
// content/questionBuilder.ts
//
// Pure functions that generate interview questions and structured markdown
// from extracted spec signals. No I/O. No side effects.
// ─────────────────────────────────────────────────────────────────────────────

import { detectGaps } from "./analyzer.js";
import { extractSpec } from "./parser.js";
import type { ExtractedSpec } from "./parser.js";

/** Six structured questions focused on algorithmic thinking. */
export function buildAlgorithmQuestions(topic: string, _content: string, _focus: string): string[] {
  return [
    `Looking at ${topic}, what algorithmic pattern or technique would you apply here, and why? ` +
    `Walk me through how you recognised the pattern from the problem constraints.`,

    `Describe your step-by-step approach to solving ${topic}. ` +
    `Focus on: how you set up the initial state, what invariant you maintain through each iteration, ` +
    `and how you know when to stop.`,

    `Analyse the time and space complexity of your solution to ${topic}. ` +
    `Justify each bound — don't just state it. ` +
    `Is there a more space-efficient version, even at a cost to time?`,

    `What edge cases does ${topic} need to handle? ` +
    `For each one: what goes wrong in a naive implementation, and how does your solution address it?`,

    `What are the most common off-by-one errors or logical mistakes candidates make when implementing ${topic}? ` +
    `Walk through a specific mistake and show how you would catch it.`,

    `How would you design test cases for ${topic}? ` +
    `Give at least one minimal example, one edge case, and one large-input scenario.`,
  ];
}

export function polishContent(topic: string, raw: string, focus: string): string {
  const spec = extractSpec(raw);
  const gaps = detectGaps(raw);
  const lines: string[] = [];

  lines.push(`# ${topic} — Structured Spec`, "");
  lines.push(`**Interview focus:** ${focus}`, "");

  lines.push("## API Endpoints", "");
  if (spec.endpoints.length > 0) {
    lines.push("| Method | Path | Description |");
    lines.push("|--------|------|-------------|");
    for (const endpoint of spec.endpoints) {
      lines.push(`| \`${endpoint.method}\` | \`${endpoint.path}\` | ${endpoint.hint || "—"} |`);
    }
  } else {
    lines.push("*No explicit HTTP endpoints detected — see original spec below.*");
  }
  lines.push("");

  if (spec.models.length > 0) {
    lines.push("## Data Models", "");
    for (const model of spec.models) {
      lines.push(`### ${model.name}`, "");
      lines.push("| Field | Type |");
      lines.push("|-------|------|");
      for (const field of model.fields) {
        lines.push(`| \`${field.name}\` | ${field.type} |`);
      }
      lines.push("");
    }
  }

  lines.push("## Business Rules", "");
  if (spec.rules.length > 0) {
    spec.rules.forEach((rule, index) => lines.push(`${index + 1}. ${rule}`));
  } else {
    lines.push("*No explicit business rules detected — see original spec below.*");
  }
  lines.push("");

  if (spec.notes.length > 0) {
    lines.push("## Implementation Notes", "");
    for (const note of spec.notes) {
      lines.push(`- ${note}`);
    }
    lines.push("");
  }

  if (gaps.length > 0) {
    lines.push("## Detected Gaps (not addressed in the spec)", "");
    lines.push("These topics are absent from the specification. Use them as interview angles.", "");
    for (const gap of gaps) {
      lines.push(`- ${gap}`);
    }
    lines.push("");
  }

  lines.push("---", "");
  lines.push("## Original Spec", "");
  lines.push(raw.trim());

  return lines.join("\n");
}

/** Six structured questions grounded in API spec signals. */
export function buildQuestions(
  topic: string,
  spec: ExtractedSpec,
  gaps: string[],
  focus: string,
): string[] {
  const endpointList = spec.endpoints.length > 0
    ? spec.endpoints.map((e) => `\`${e.method} ${e.path}\``).join(", ")
    : `the ${topic} endpoints`;

  const fieldSample = spec.models.flatMap((m) => m.fields.map((f) => f.name)).slice(0, 4);
  const fieldList   = fieldSample.length > 0 ? fieldSample.join(", ") : "the request fields";

  const ruleSnippet = spec.rules.length > 0 ? `"${spec.rules[0]}"` : "the business rules in the spec";

  const topGaps = gaps.slice(0, 3).join(", ");

  return [
    `Looking at the ${topic} spec — ${endpointList} — what are the most critical missing pieces ` +
    `from a ${focus} perspective that you would address before going to production?` +
    (topGaps ? ` Consider in particular: ${topGaps}.` : ""),

    `The ${topic} API accepts fields like ${fieldList}. ` +
    `What input validation, sanitisation, and error response strategy would you put in place, ` +
    `and how would you communicate failures clearly to API consumers?`,

    `One business rule states ${ruleSnippet}. ` +
    `How would you implement and test this so that new rules can be added or existing ones changed ` +
    `without modifying the core calculation logic?`,

    `What logging, metrics, and alerting would you instrument in ${topic} ` +
    `so an on-call engineer can diagnose a spike in errors or latency within minutes, ` +
    `without access to the codebase?`,

    `Walk me through every failure mode of ${endpointList}. ` +
    `For each one: what is the impact on the caller, and how would you degrade gracefully ` +
    `instead of returning a 500?`,

    `${topic} currently stores its data in memory on startup. ` +
    `What would need to change — and in what order — if the service had to: ` +
    `(a) survive restarts without data loss, ` +
    `(b) run as multiple instances behind a load balancer, ` +
    `(c) allow live updates without a redeploy?`,
  ];
}

export const buildApiQuestions = buildQuestions;

// ─────────────────────────────────────────────────────────────────────────────
// drills/contentBuilder.ts
//
// Pure functions that build the rubric context and recall prompt for a drill
// session from past evaluation data. No I/O. No side effects.
// ─────────────────────────────────────────────────────────────────────────────

import type { Evaluation, Mistake } from "@mock-interview/shared";

export interface RecallContext {
  knownMistakes: Array<{ mistake: string; pattern: string; fix: string }>;
  weakAreas:     Array<{ question: string; previousScore: number; previousFeedback: string }>;
}

/**
 * Build the `customContent` string stored on the drill session.
 * This serves as the rubric context for `evaluate_answer`.
 */
export function buildDrillCustomContent(
  topic:       string,
  sourceId:    string,
  sourceDate:  string,
  avgScore:    string,
  weakEvals:   Evaluation[],
  mistakes:    Mistake[],
): string {
  const lines: string[] = [
    `# Drill Session — ${topic}`,
    "",
    `**Source session:** ${sourceId} (${sourceDate.slice(0, 10)})`,
    `**Avg score in source session:** ${avgScore}`,
    "",
    "## Weak Questions (score < 4)",
    "",
  ];

  weakEvals.forEach((e, i) => {
    lines.push(`### Question ${i + 1} — score ${e.score}/5`, "");
    lines.push(`**Question:** ${e.question}`, "");
    lines.push(`**Previous feedback:** ${e.feedback}`);
    if (e.strongAnswer) {
      lines.push("", `**Strong answer looks like:** ${e.strongAnswer}`);
    }
    lines.push("");
  });

  if (mistakes.length > 0) {
    lines.push("## Known Mistake Patterns", "");
    mistakes.forEach((m) => {
      lines.push(`- **${m.mistake}**`);
      lines.push(`  - Pattern: ${m.pattern}`);
      lines.push(`  - Fix: ${m.fix}`);
    });
  }

  return lines.join("\n");
}

/**
 * Build the `recallContext` object surfaced to the orchestrator so it can run
 * the recall step before asking the first drill question.
 */
export function buildRecallContext(weakEvals: Evaluation[], mistakes: Mistake[]): RecallContext {
  return {
    knownMistakes: mistakes.map((m) => ({
      mistake: m.mistake,
      pattern: m.pattern,
      fix:     m.fix,
    })),
    weakAreas: weakEvals.map((e) => ({
      question:         e.question,
      previousScore:    e.score,
      previousFeedback: e.feedback,
    })),
  };
}

// ─────────────────────────────────────────────────────────────────────────────
// exercises/assessment.ts
//
// Pure function that checks whether an exercise is appropriate for the candidate
// and builds a progression roadmap when it is not. No I/O. No side effects.
// ─────────────────────────────────────────────────────────────────────────────

import type { Exercise, ExercisePrerequisite } from "@mock-interview/shared";

export interface ComplexityAssessment {
  tooHard:            boolean;
  reason:             string | null;
  unmetPrerequisites: string[];
  roadmap:            Array<{ order: number; name: string; difficulty: number; reason: string }>;
}

/**
 * Determine whether an exercise is too hard for the candidate right now.
 *
 * Rules:
 *  - `tooHard = true` when difficulty ≥ 4 OR any named prerequisite does not
 *    yet exist in `existingExercises`.
 *  - `roadmap` is the ordered list of prerequisites by difficulty, so the LLM
 *    can propose a clear progression.
 */
export function assessComplexity(
  difficulty: number,
  prerequisites: ExercisePrerequisite[],
  existingExercises: Exercise[],
): ComplexityAssessment {
  const existingNames    = new Set(existingExercises.map((e) => e.name));
  const unmetPrerequisites = prerequisites
    .map((p) => p.name)
    .filter((name) => !existingNames.has(name));

  const resolvedPrereqs = prerequisites
    .map((p) => {
      const found = existingExercises.find((e) => e.name === p.name);
      return { name: p.name, difficulty: found?.difficulty ?? 0, reason: p.reason };
    })
    .sort((a, b) => a.difficulty - b.difficulty);

  const roadmap = resolvedPrereqs.map((p, i) => ({
    order:      i + 1,
    name:       p.name,
    difficulty: p.difficulty,
    reason:     p.reason,
  }));

  const tooHard = difficulty >= 4 || unmetPrerequisites.length > 0;
  const reason  = tooHard
    ? unmetPrerequisites.length > 0
      ? `Prerequisites not yet created: ${unmetPrerequisites.join(", ")}`
      : `Difficulty ${difficulty}/5 — recommend completing prerequisites first`
    : null;

  return { tooHard, reason, unmetPrerequisites, roadmap };
}

// ─────────────────────────────────────────────────────────────────────────────
// exercises/markdown.ts
//
// Pure function that renders an Exercise record as structured markdown.
// No I/O. No side effects.
// ─────────────────────────────────────────────────────────────────────────────

import type { Exercise } from "@mock-interview/shared";

export const DIFFICULTY_LABELS: Record<number, string> = {
  1: "Trivial",
  2: "Easy",
  3: "Medium",
  4: "Hard",
  5: "Very Hard",
};

export interface ExerciseMarkdownOpts {
  learningGoal:       string;
  problemStatement:   string;
  steps:              string[];
  evaluationCriteria: string[];
  hints:              string[];
  relatedConcepts:    string[];
}

export function buildExerciseMarkdown(exercise: Exercise, opts: ExerciseMarkdownOpts): string {
  const diffLabel     = DIFFICULTY_LABELS[exercise.difficulty] ?? "Medium";
  const tagSection    = exercise.tags.length > 0 ? exercise.tags.join(", ") : "_None_";
  const prereqSection = exercise.prerequisites.length > 0
    ? exercise.prerequisites.map((p) => `- **${p.name}** — ${p.reason}`).join("\n")
    : "_None — this is a self-contained exercise._";

  const stepsSection   = opts.steps.map((s, i) => `${i + 1}. ${s}`).join("\n");
  const evalSection    = opts.evaluationCriteria.map((c) => `- ${c}`).join("\n");
  const hintsSection   = opts.hints.length > 0
    ? opts.hints.map((h) => `- ${h}`).join("\n")
    : "_No hints — try to work through it first._";
  const conceptsSection = opts.relatedConcepts.map((c) => `- ${c}`).join("\n");
  const meaningSection  = exercise.problemMeaning.map((m) => `- ${m}`).join("\n");

  return `# Exercise: ${exercise.name}

## Topic / Language / Difficulty
**Topic:** ${exercise.topic}
**Language:** ${exercise.language}
**Difficulty:** ${exercise.difficulty}/5 — ${diffLabel}
**Tags:** ${tagSection}

## Real-World Context
**Scenario:** ${exercise.scenario}

### Why this matters in production
${meaningSection}

## Learning Goal
${opts.learningGoal}

## Prerequisites
${prereqSection}

## Problem Statement
${opts.problemStatement}

## Implementation Steps
${stepsSection}

## What a Good Solution Looks Like
${evalSection}

## Hints
${hintsSection}

## Related Concepts
${conceptsSection}
`;
}

// ─────────────────────────────────────────────────────────────────────────────
// scope/builder.ts
//
// Pure functions that build reusable scoped-interview content blocks.
// No I/O. No side effects.
// ─────────────────────────────────────────────────────────────────────────────

const DEPTH_DESCRIPTION: Record<string, string> = {
  conceptual: "Verbal explanation only — no code required. Candidate should explain the mental model.",
  implementation: "Candidate writes pseudocode or real code. Correctness and structure matter.",
  "trace-through-code": "Candidate traces through a provided snippet step by step. Focus on execution order and state.",
  mixed: "Mix of verbal explanation and code tracing. Adapt depth per question.",
};

function buildCriterion(area: string): string {
  return `**${area}**: Candidate must explain this clearly and give a concrete example. ` +
    "Probe if the answer is vague or generic.";
}

export function buildScopeContent(opts: {
  topic: string;
  focusAreas: string[];
  weakSpots: string[];
  depth: string;
  outOfScope: string[];
  sessionGoal: string;
}): string {
  const lines: string[] = [];

  lines.push(`# Study Scope: ${opts.topic}`, "");

  lines.push("## Focus Areas");
  for (const area of opts.focusAreas) {
    lines.push(`- ${area}`);
  }
  lines.push("");

  lines.push(`## Depth: ${opts.depth}`);
  lines.push(DEPTH_DESCRIPTION[opts.depth] ?? DEPTH_DESCRIPTION.mixed);
  lines.push("");

  lines.push("## Evaluation Criteria");
  for (const area of opts.focusAreas) {
    lines.push(`- ${buildCriterion(area)}`);
  }
  lines.push("");

  if (opts.weakSpots.length > 0) {
    lines.push("## Known Weak Spots (probe these specifically)");
    for (const spot of opts.weakSpots) {
      lines.push(`- ${spot}`);
    }
    lines.push("");
  }

  if (opts.outOfScope.length > 0) {
    lines.push("## Out of Scope");
    for (const item of opts.outOfScope) {
      lines.push(`- ${item}`);
    }
    lines.push("");
  }

  lines.push("## Session Goal");
  lines.push(opts.sessionGoal);
  lines.push("");

  return lines.join("\n");
}

export function deriveSessionGoal(_topic: string, focusAreas: string[], depth: string): string {
  const areaList = focusAreas.slice(0, 3).join(", ");
  const extra = focusAreas.length > 3 ? `, and ${focusAreas.length - 3} more` : "";
  return (
    `Candidate can explain ${areaList}${extra} without prompting. ` +
    `Depth: ${depth}. No drifting into unrelated areas.`
  );
}
